INSERT INTO jobs (job_name, industry, city, company_type, salary_min, salary_max, skills, soft_skills, is_fresh_friendly, friendly_level, jd_content, core_duties, education, major, experience, post_type, bonus_skills, salary_range, post_time, apply_deadline, jd_link, post_category, party_label) VALUES ('培训经理 - 南昌（社招）', '互联网 / IT', '南昌', '民营企业', 10000, 15000, '1. 可独立完成培训体系搭建、课程开发、项目全流程执行与效果评估；2. 熟练使用Office办公软件，可完成课件制作、数据复盘与报告输出；3. 具备内部讲师团队建设、激励体系搭建能力', '1. 具备优秀的项目统筹与落地能力，目标导向；2. 具备良好的跨部门沟通协调能力，可联动业务部门推动培训成果落地；3. 学习能力强，具备创新思维，适配年轻化团队特性', 0, '一般', '1. 培训体系搭建：结合公司战略，搭建并迭代培训体系，制定年度/季度培训规划与预算方案；2. 课程开发与优化：主导核心课程开发，沉淀内部案例与知识资产；整合外部优质培训资源，适配业务快速迭代需求；3. 培训项目落地：统筹各类培训项目的全流程执行，包括需求调研、方案设计、组织实施、效果评估（柯氏四级评估）与复盘优化；4. 内训师团队建设：挖掘并培养内部业务骨干、管理层成为内训师，搭建内训师选拔、赋能、激励体系，提升内训师授课能力与课程质量；5. 培训效果转化：建立培训效果跟踪机制，联动业务部门推动培训成果落地，通过技能考核、业绩关联、行为改变等维度验证培训价值，助力员工成长与业务增长；6. 学习氛围营造：策划各类学习活动，搭建内部学习交流平台，推动学习型组织建设，契合新媒体行业年轻化团队特性', 'OD 组织发展支持', '大专及以上', '人力资源管理、工商管理、教育学等相关专业优先', '3年以上培训相关工作经验，有新媒体、互联网、营销类行业培训经验者优先，熟悉300人左右规模企业培训体系搭建逻辑', '社招（应届生可投）', '有新媒体/互联网营销行业培训经验；有300人以上规模企业培训体系搭建经验', '10k-15k/月', '46112', NULL, 'BOSS直聘平台获取', 'OD类', '甲方（企业自有 HR 岗）'), ('培训经理 - 厦门（社招）', '快消', '厦门', '民营企业', 7000, 11000, '1. 可独立建立和完善培训体系，开发标准化培训课程；2. 熟练使用Office办公软件，可完成课件、短视频、手册等培训物料制作；3. 具备培训考核机制搭建与效果落地能力', '1. 具备优秀的表达能力和课程开发能力，台风稳健；2. 热爱陶瓷文化和美食文化，学习能力强；3. 工作认真负责，具备良好的项目落地能力', 0, '一般', '1. 负责建立和完善加盟商及门店员工的培训体系；2. 开发标准化培训课程：白瓷文化知识、产品知识、销售技巧、服务礼仪、陈列技巧、咖啡/茶饮制作标准；3. 负责组织和实施各类培训活动：集中培训、线上培训、到店带教；4. 建立培训考核机制，确保培训效果落地；5. 配合米其林内容中心，将培训内容转化为短视频、手册等素材', 'OD 组织发展支持', '大专及以上', '无强制专业限制', '3年以上培训经验，有连锁零售、餐饮或消费品行业培训经验者优先', '社招（应届生可投）', '有连锁零售/餐饮/消费品行业培训经验；有短视频制作、课程物料开发经验', '7k-11k/月', '46112', NULL, 'BOSS直聘平台获取', 'OD类', '甲方（企业自有 HR 岗）'), ('培训经理 - 通辽（社招）', '其他', '通辽', '民营企业', 4000, 9000, '1. 具备优秀的课程开发与教学设计能力，能够独立完成培训材料的编写；2. 熟练使用Office办公软件，可完成课件制作、培训档案建立与数据整理；3. 熟悉咨询业务流程，具备培训效果跟踪与优化能力', '1. 沟通能力强，能够有效协调内外部资源，推动培训项目的顺利进行；2. 具有较强的分析判断能力和问题解决能力，能够根据培训反馈及时调整策略；3. 工作认真负责，目标导向，具备良好的项目管理能力', 0, '一般', '1. 负责设计和实施针对法律咨询团队的专业培训计划，提升团队整体业务能力；2. 根据公司业务需求，开发新的培训模块和课程内容，确保培训材料的前沿性和实用性；3. 组织和协调内外部培训资源，包括但不限于邀请行业专家、安排外部培训等，提升培训质量；4. 跟踪培训效果，通过考核和反馈机制不断优化培训流程和内容；5. 建立和维护培训档案，记录培训成果，为团队发展提供数据支持', 'OD 组织发展支持', '大专及以上', '无强制专业限制，有销售/咨询行业背景优先', '3-5年，至少3年以上培训相关工作经验，有成功培训项目案例者优先', '社招（应届生可投）', '有销售/法律咨询行业培训经验；有成功的大型培训项目落地案例', '4k-9k/月', '46112', NULL, 'BOSS直聘平台获取', 'OD类', '甲方（企业自有 HR 岗）'), ('hrbp助理 - 濮阳（社招）', '互联网 / IT', '濮阳', '民营企业', 3000, 5000, '1. 具备较强的数据处理和文档管理能力；2. 熟练使用办公软件；3. 具备基础的人力资源全流程事务执行能力', '1. 具备良好的执行力与组织协调能力，能高效完成各项支持工作；2. 沟通表达良好，能够与不同层级员工建立有效互动；3. 具有较强的责任心和保密意识，遵守职业规范；4. 学习能力强，能快速适应工作节奏并融入团队协作', 1, '友好', '1. 协助HRBP开展人力资源相关工作，支持组织运营与团队管理；2. 参与招聘、入职、转正、调动及离职等员工全周期事务的执行；3. 协助推进绩效管理、人才发展与组织文化建设相关工作；4. 整理人力资源数据，提供基础性业务支持与信息维护；5. 配合处理员工关系事务，保障内部沟通顺畅与制度落实', '招聘全流程执行、员工关系支持、薪酬绩效支持、OD 组织发展支持、招聘数据分析', '大专及以上', '无强制专业限制', '经验不限', '社招（应届生可投）', '有人力资源管理师相关证书；有HR相关实习/工作经验', '3k-5k/月', '46112', NULL, 'BOSS直聘平台获取', 'HRBP类', '甲方（企业自有 HR 岗）'), ('hrbp助理 - 邢台（社招）', '快消', '邢台', '民营企业', 4000, 6000, '1. 熟练使用办公软件，具备招聘漏斗数据分析能力；2. 熟悉人力资源专业模块，掌握1-2个人力资源专业模块；3. 具备基础的招聘需求拆解与岗位画像搭建能力', '1. 对业务战略有深入理解，能站在业务部门角度实施人力资源战略落地；2. 较强的项目管理和协作推进能力，能以终为始提出方案，解决业务关键痛点；3. 具有人际敏感度，良好地协同能力，结构化思维，出色的学习能力和自驱力，充满好奇心', 1, '友好', '1. 负责公司人事管理工作，包括员工入职、离职等流程；参与制定和完善公司人事制度，确保人事活动的合规性；2. 协助处理员工关系，维护良好的工作氛围；3. 支持基础、后端偏专业类型岗位的交付，独立负责招聘需求和岗位画像的勾兑，分析招聘渠道适配性并优化，具备招聘漏斗数据分析意识，可根据数据诊断提出解决方案；4. 负责培训内容的完善与效果评估', '招聘全流程执行、渠道拓展与运营、简历筛选与面试、员工关系支持、招聘数据分析、OD 组织发展支持', '本科及以上', '无强制专业限制，人事招聘管理和培训管理相关经验优先', '经验不限', '社招（应届生可投）', '有人力资源管理师相关证书；有零售/快消行业HRBP经验', '4k-6k/月', '46112', NULL, 'BOSS直聘平台获取', 'HRBP类', '甲方（企业自有 HR 岗）');